  --purple-500: #9982d8;
  --purple-600: #876ad1;
  --purple-700: #7553cb;
  --purple-800: #633bc4;
  --purple-900: #5122bd;

  --monospace-font: "JetBrains Mono", "Fira Code", "Hack", "Source Code Pro",
    "SF Mono", "Inconsolata", monospace;

  --dark-border: rgba(200, 200, 25, 0.2);
  --max-width: 1280px;

  --system-font: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI",
    Roboto, Oxygen, Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif;

  --horizontal-padding: 3rem;
  --vertical-padding: 4rem;
  --line-height: 1.4;

  --phone: 600px;
  --tablet: 900px;
  --list-padding: 0.9em;
  --list-item-padding: 0.375em;
  --navbar-height: 60px;
