* {
  box-sizing: border-box;
}

head,
body,
:root {
  margin: 0 auto;
  padding: 0;
  font-family: var(--system-font);
}

html.dark {
  background: #14151b;
}

html:not(.dark) {
  background: #f9fafb;
}

html {
  height: 100vh;
  overflow-y: scroll;
  overflow-x: hidden;
  line-height: 1.5;
  text-size-adjust: 100%;
  font-family: system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizelegibility;
  /* touch-action: manipulation; */
}

a {
  color: inherit;
  text-decoration: none;
}
a.expand {
  transition: transform 0.1s linear;
}

a.expand:hover {
  /* text-decoration: underline; */
  transform: scale(1.06, 1.06);
  transform-origin: center;
}

.mono {
  font-family: var(--monospace-font) !important;
}

.Navigation ul {
  white-space: nowrap;
  display: flex;
  gap: 2rem;
  list-style: none;
}

.NavText {
  /* color: #fbf0df; */

  display: block;
  font-weight: 500;
  font-size: 1.2rem;
}

#HeaderInstallButton {
  margin-left: 2.4rem;
}

#logo {
  max-width: 70px;
  margin: auto 0;
}

#logo-text {
  max-width: 96px;
}

/* header { */
/* display: grid; */
/* grid-template-columns: auto max-content; */
/* background-color: var(--black); */
/* padding: 1.5rem 3rem; */
/* align-items: center; */
/* color: white; */
/* } */

#HeaderInstallButton:hover {
  cursor: pointer;
  transform: scale(1.06);
}

#HeaderInstallButton {
  transition: transform 0.1s linear;
  background: #00a6e1;
  padding: 8px 16px;
  border-radius: 100px;
  color: black;
  font-weight: 500;
}

.BarGraph-subheading {
  font-size: 0.9rem;
  color: rgb(135, 134, 134);
  margin: 0;
}
.bun-bar {
  background-color: #f9f1e1;
  box-shadow: inset 1px 1px 3px #ccc6bb;
  background-image: url(data:image/svg+xml;base64,);
  background-repeat: no-repeat;
  background-size: 56px 48.8px;
  background-position: 19px 46%;
}

.Tab:hover,
.Tab.active {
  border-bottom-color: var(--gray-400);
  background-color: var(--gray-800);
}

.CardContent {
  position: relative;
}
.DemphasizedLabel {
  text-transform: uppercase;
  white-space: nowrap;
}

#frameworks {
  display: flex;
}

.FrameworksGroup {
  display: grid;
  grid-template-rows: auto 40px;
  gap: 0.5rem;
}

.DemphasizedLabel {
  color: #7a7a7a;
  font-weight: 300;
}

.FrameworksList {
  display: grid;
  grid-template-columns: repeat(2, 40px);
  gap: 3.5rem;
  align-items: center;
}

#cards {
  display: grid;
}

.Tag {
  --background: rgba(31, 31, 132, 0.15);
  background-color: var(--background);
  border-radius: 4px;
  padding: 4px 4px;
  border: none;
  line-height: 1;
  color: black;
  text-decoration: none !important;
  display: inline-block;
  font-family: var(--monospace-font) !important;
  box-shadow: 0px 1px 0px rgb(111 111 111);
}

.Tag--Command {
  --background: #111;
  font-weight: medium;
  color: rgb(163, 255, 133);
}

.Tag--Command:before {
  content: "❯" / "";
  color: rgba(255, 255, 255, 0.35);
  margin-top: auto;
  margin-bottom: auto;
  margin-right: 1ch;
  margin-left: 0.5ch;
  display: inline-block;
  transform: translateY(-1px);
}

.Tag--WebAPI {
  --background: #29b6f6;
}

.Tag--NodeJS {
  --background: rgb(130, 172, 108);
}

.Tag--TypeScript {
  --background: rgb(69, 119, 192);
  color: white;
}

.Tag--React {
  color: rgb(130, 216, 247);
  --background: #333;
}

.Tag--React:before {
  color: rgba(130, 216, 247, 0.5);
  content: "<" / "";
}

.Tag--React:after {
  color: rgba(130, 216, 247, 0.5);
  content: ">" / "";
}

.Tag--Bun {
  --background: #e600e5;
  color: white;
}

@media (max-width: 1024px) {
  :root {
    --max-width: 100%;
    --horizontal-padding: 16px;
    --vertical-padding: 2rem;
    --line-height: 1.6;
  }

  main {
    grid-template-columns: auto;
    grid-template-rows: auto auto auto;
  }

  ul {
    padding: 0;
    list-style: none;
  }

  #logo-text,
  #HeaderInstallButton {
    display: none;
  }
}

.Zig {
  transform: translateY(15%);
  display: inline;
  vertical-align: baseline;
}

.CodeBlock {
  margin-top: 0px;
  margin-bottom: 0px;
  padding: 10px 0px;
  background-color: var(--gray-800);
  border-radius: 5px;
  overflow-x: scroll;
  -ms-overflow-style: none; /* Internet Explorer 10+ */
  scrollbar-width: none; /* Firefox */
}
.CodeBlock::-webkit-scrollbar {
  display: none; /* Safari and Chrome */
}

/* Memory leak debug post avoid/prefer styles */
.avoid-example > .CodeBlock {
  position: relative;
}
.avoid-example > .CodeBlock::before {
  content: "";
  position: absolute;
  inset: 0;
  background-color: rgba(220, 38, 38, 0.08);
  pointer-events: none;
  height: 100%;
  z-index: 1;
  border: 1px solid rgb(185, 28, 28);
  border-radius: 0.25rem;
}

.dark {
  color-scheme: dark;
}

.dark .avoid-example > .CodeBlock::before {
  background-color: rgba(185, 28, 28, 0.12);
}

body {
  color-scheme: light;
}
.dark,
.dark body {
  color-scheme: dark;
}

.prefer-example .CodeBlock {
  position: relative;
}
.prefer-example > .CodeBlock::before {
  content: "";
  position: absolute;
  inset: 0;
  background-color: rgba(22, 163, 74, 0.08);
  pointer-events: none;
  height: 100%;
  z-index: 1;
  border: 1px solid rgb(22, 163, 74);
  border-radius: 0.25rem;
}

.dark .prefer-example > .CodeBlock::before {
  background-color: rgba(22, 163, 74, 0.12);
}

.CodeBlock > * {
  width: fit-content;
  min-width: 100%;
}
.CodeBlock .line {
  height: 15px;
  white-space: pre;
}

.CodeBlockShell .shiki code .line:last-child::before {
  content: "$ " !important;
  /* color: black; */
  color: white;
  opacity: 0.5;
}
/* .dark .CodeBlockShell .shiki code .line:last-child::before {
  color: white;
} */
.CodeBlockPowershell .shiki code .line:last-child::before {
  content: "> " !important;
  /* color: black; */
  color: white;
  opacity: 0.5;
}
/* .dark .CodeBlockPowershell .shiki code .line:last-child::before {
  color: white;
} */
.CodeBlockResults .shiki * {
  opacity: 0.8;
}
.CodeBlockDiff .shiki code .line::before {
  content: " " !important;
  opacity: 0.5;
}
.CodeBlock > div {
  /* border-bottom: 1px solid #525567; */
  overflow: hidden;
}

.CodeBlock > div:first-child {
  border-top-left-radius: 5px;
  border-top-right-radius: 5px;
}
.CodeBlock > div:last-child {
  border-bottom-left-radius: 5px;
  border-bottom-right-radius: 5px;
  border-bottom: none;
}
.CodeBlock .shiki {
  /* line-height: 20px;  !important; */
  line-height: 20px;
  padding: 3px 2.5rem 3px 1rem;
  border-radius: 0px;
  font-family: var(--monospace-font);
  margin-top: 0px;
  margin-bottom: 0px;
}
.CodeBlock .CopyIcon {
  top: -1px;
}
.CodeBlock + .CodeBlock {
  margin-top: 15px;
}

.CodeBlock code {
  font-size: inherit;
}
@media (max-width: 640px) {
  /* .CodeBlock code { */
  /* font-size: 0.8em; */
  /* } */
}
@media (max-width: 768px) {
  .CodeBlock > div {
    border-radius: 0px !important;
    border-top-left-radius: 0px;
    border-top-right-radius: 0px;
    border-bottom-left-radius: 0px;
    border-bottom-right-radius: 0px;
  }
}
.CodeTabs .CodeBlock {
  border-top-left-radius: 0px !important;
  border-top-right-radius: 0px !important;
}
.CodeTabs .CodeBlock > div {
  border-radius: 0px !important;
}
.CodeTabs {
  border-radius: 5px;
  overflow: hidden;
}
.CodeTabs .CodeBlockTab {
  display: none;
}

