.CodeTab:hover {
  color: white;
}
.CodeTab.active {
  color: white;
}

.CodeBlockTab {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: flex-start;
  text-align: left;
  font-size: 12px;
  padding: 0px 1rem 5px 1rem;
  margin-top: -6px;
  margin-bottom: 8px;
  border-bottom: 1px solid transparent;
  background-color: var(--gray-800);
  border-top-left-radius: 5px;
  border-top-right-radius: 5px;
  color: #ffffff80;
  border-bottom: 1px solid #525567;
}
.CodeBlockTab p {
  margin: 0;
  padding-top: 5px;
  padding-bottom: 5px;
  line-height: 18px;
  padding-right: 12px;
}
.CodeTabItem {
  display: none;
}
.CodeTabItem.active {
  display: block;
}
