  padding: 8px 12px;
}

img {
  object-fit: contain;
}

.visually-hidden {
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  height: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
  width: 1px;
}

.prose > * {
  --tw-prose-body: red !important;
}
/* .prose p { */
/* color: var(--gray-800); */
/* } */
.prose :where(a):not(:where([class~="not-prose"] *)) {
  font-weight: unset !important;
}

.prose hr {
  margin-top: 2em;
  margin-bottom: 2em;
}
.prose code {
  background-color: var(--gray-200);
  border: 1px solid var(--gray-300);
  padding: 2px 3px;
  border-radius: 0.2em;
  font-weight: unset !important;
}
.dark .prose code {
  background-color: var(--gray-700);
  border: 1px solid var(--gray-700);
}
.prose pre {
  overflow-x: hidden !important;
}
.prose pre code,
.dark .prose pre code {
  background-color: unset;
  padding: unset;
  border-radius: unset;
  font-weight: unset;
  border: unset;
}
.prose > img {
  border-radius: 5px;
  margin: auto;
}
@media (max-width: 768px) {
  .prose > img {
    margin-left: calc(-1 * var(--horizontal-padding));
    border-radius: 0px;
    max-width: none;
    width: 100vw;
  }
  .prose li figure {
    width: 100vw !important;
    margin-left: calc(
      -1 * (var(--horizontal-padding) + var(--list-item-padding) +
            var(--list-padding))
    ) !important;
  }

  .prose > p > img {
    border-radius: 0px;
  }
  .prose .details {
    margin-left: calc(-1 * var(--horizontal-padding));
    border-radius: 0px;
    max-width: none;
    width: 100vw;
  }
}
.prose li > * {
  margin-top: 2px !important;
  margin-bottom: 2px !important;
}
.prose li p {
  padding-bottom: 8px;
  line-height: 1.5;
}
.prose li > *:last-child {
  margin-bottom: 1em;
}
/* .prose figure {
  width: 100%;
  margin: auto;
} */
.prose figure img {
  margin-top: 0px !important;
  margin-bottom: 0px !important;
  margin-left: auto;
  margin-right: auto;
}
.prose li img,
.prose li figure {
  margin: unset;
  margin-top: 1em;
}

.prose details {
  margin-top: 1.25em;
  margin-bottom: 1.25em;
  border-left: 1px solid var(--gray-300);
  padding-left: 15px;
}
.prose summary::marker {
  display: none;
}
.prose :where(code):not(:where([class~="not-prose"] *)):before,
.prose :where(code):not(:where([class~="not-prose"] *)):after {
  content: unset !important;
}
.prose :where(ul):not(:where([class~="not-prose"] *)) {
  list-style-type: square !important;
  padding-left: var(--list-padding) !important;
}
.prose :where(ul > li):not(:where([class~="not-prose"] *)) {
  padding-left: var(--list-item-padding) !important;
}
#blog-post .prose h1 {
  padding-bottom: 6px;
  border-bottom: 1px solid #00000018;
}
#blog-post .prose h2 {
  padding-bottom: 3px;
  border-bottom: 1px solid #00000018;
}
.prose :where(ol):not(:where([class~="not-prose"] *)) {
  padding-left: 1.22em !important;
}
.prose :where(ol > li):not(:where([class~="not-prose"] *)) {
  padding-left: var(--list-item-padding) !important;
}
.prose :where(blockquote):not(:where([class~="not-prose"] *)) {
  border-left: 1px solid var(--gray-200);
  font-weight: normal;
}
.prose a:hover {
  transform: none;
  color: var(--link-hover-color);
}
.dark .prose a {
  color: inherit;
}
.dark .prose a:hover {
  color: inherit;
}
.expand-on-hover > * {
  transition: transform 0.1s linear;
}
.expand-on-hover:hover > * {
  transform: scale(1.06, 1.06);
  transform-origin: center;
}

.prose .anchored:hover a {
  transform: none;
  color: inherit;
}
.prose h1 {
  border-bottom: 1px solid var(--gray-200);
  padding-bottom: 8px;
}
.prose h2 {
  border-bottom: 1px solid var(--gray-200);
  padding-bottom: 4px;
}
.dark .prose h1,
.dark .prose h2 {
  border-color: var(--gray-700);
  color: var(--gray-200);
}
.prose h5,
.prose h6 {
  font-weight: bold;
}

/* .prose img {
  border-radius: 5px;
} */
@media (max-width: 640px) {
  .prose > img {
    height: auto;
    width: 100vw;
  }
}

@media (min-width: 640px) {
  .prose img {
    border-radius: 5px;
  }
}

.callout > *:first-child {
  margin-top: 0;
}
.callout > *:last-child {
  margin-bottom: 0;
}
.callout > figure {
  margin-top: 1.25rem;
}
.anchored:hover a:last-child::after {
  content: "#";
  opacity: 0.3;
  margin-left: 0.25em;
  font-weight: normal;
  cursor: pointer;
  /* position: "absolute"; */
}
.rawhtml > * {
  margin: auto;
}

/* #doc-menu code {
  background-color: var(--gray-100);
  border: 1px solid var(--gray-300);
  padding: 1px 3px;
  border-radius: 0.2em;
  font-weight: unset !important;
} */
.BlogCard:first-child .BlogCardContents {
  border-top-color: transparent;
}
.BlogCard:hover .BlogCardContents {
  border-top-color: transparent;
}
.BlogCard:hover + .BlogCard .BlogCardContents {
  border-top-color: transparent;
}
.Params {
  margin: 0;
}
.Params:nth-child(even) .ParamsName,
.Params:nth-child(even) .ParamsContent,
.Params:nth-child(even) .ParamsSpacerLast {
  background-color: var(--gray-100);
}

.Params .ParamsContent > *:first-child {
  margin-top: 0;
}
.Params .ParamsContent > *:last-child {
  margin-bottom: 0;
}

.dark .anchor-menu code {
  color: var(--gray-400) !important;
  text-decoration: none;
}

.readme h1:not(:first-of-type) {
  padding-top: 70px;
}

@keyframes loaderbar {
  0% {
    transform: scaleX(0);
  }
  100% {
    transform: scaleX(1);
  }
}

.text-outline {
  text-shadow: 1px 1px 3px black;
}

a.link-always-underline {
  text-decoration: underline;
  text-decoration-thickness: 0.1rem;
}

.HorizontalGraphItem-grid {
  margin-top: 4px;
  display: grid;
  grid-template-columns: auto min-content min-content;
  overflow: hidden;
  grid-template-rows: 36px;
}
.HorizontalGraphItem-grid .counter {
  align-items: center;
}

/* .Crumb .CodeBlock {
  height: 0px;
  overflow: visible;
  margin-left: 500px;
} */

@media (min-width: 1024px) {
  .crumb-left > p:first-child {
    margin-top: 8px;
  }

  .crumb-right {
    /* max-width: 600px; */
    overflow: auto;
  }
  .crumb-left {
    min-width: 350px;
  }

  .crumb-left > h1,
  .crumb-left > h2,
  .crumb-left > h3 {
    margin-top: 0;
  }

  .crumb-right > figure {
    margin-top: 0px;
    margin-bottom: 0px;
  }
}

.chakra-portal {
  --inkeep-colors-grayDark-600: #282a35 !important;
}

.inline-icon {
  margin-top: 0 !important;
  margin-bottom: 0 !important;
  display: inline;
}

/* Install Code Block - Inline Shiki Styles */
.shiki-inline {
  display: inline;
  font-family: var(--monospace-font);
}

.shiki-inline .shiki {
  display: inline;
  background: transparent !important;
  padding: 0 !important;
  margin: 0 !important;
}

.shiki-inline pre {
  display: inline;
  background: transparent !important;
  padding: 0 !important;
  margin: 0 !important;
}

.shiki-inline code {
  display: inline;
  background: transparent !important;
  padding: 0 !important;
  font-size: 0.875rem;
}

/* Quick Install Shiki Styles */
.text-lg.shiki-inline code {
  font-size: 1.125rem;
}

@media (max-width: 580px) {
  /* TODO: figure out how to avoid this */
  .mobile-flex-wrap {
    flex-wrap: wrap;
  }
}

.copy-as-markdown--copied {
  animation: copy-as-markdown-copied 0.2s linear;
}

@keyframes copy-as-markdown-copied {
  0% {
    filter: invert(0.25);
  }
  100% {
    filter: invert(0);
  }
}
