enter gap-8 md:max-w-screen-sm lg:max-w-[var(--max-width)] lg:flex-row lg:justify-between"><div class="flex-1 lg:max-w-[700px]"><a href="/blog/bun-v1.3.11" class="group"><div class="-m-1 inline-block rounded-full border border-gray-400/15 p-1 group-hover:border-gray-400/30"><div class="inline-block rounded-[30px] bg-gray-600/40 px-[17px] py-[6px] text-gray-300 group-hover:bg-gray-700/70">Bun v1.3.11 is here! →</div></div></a><div class="h-[18px]"></div><h1 class="mt-0 text-start text-[28pt] font-extrabold leading-none dark:text-gray-50 md:text-[32pt] lg:text-[38pt] xl:text-[40pt]">Bun is a<!-- --> <span class="text-shadow-lg -mr-0.5 italic text-pink-200" style="text-shadow:0px 5px 6px rgba(244,114,182,0.57), 0px 5px 8px rgba(244,114,182,0.47);">fast</span> <!-- -->JavaScript<br/><span class="m-0 p-0" id="typer">all-in-one toolkit</span><span class="blink font-light">|</span></h1><script>

let handle;
function startBlink() {
  handle = setInterval(() => {
    // show/hide .blink
    const blink = document.querySelector(".blink");
    blink.style.visibility = blink.style.visibility === "hidden" ? "visible" : "hidden";
  }, 500);
}
function stopBlink() {
  const blink = document.querySelector(".blink");
  blink.style.visibility = "visible";
  clearInterval(handle);
}

const options = ["runtime", "package manager", "bundler", "test runner", "all-in-one toolkit"];

async function replaceTyper(){

  const typer = document.getElementById("typer");
  const current = typer.innerText;
  const next = options[(options.indexOf(current) + 1) % options.length];

  const CHAR_DELAY = 40;
  const WORD_DELAY = 2300;

  stopBlink();

  while(typer.innerText.length > 0) {
    typer.innerText = typer.innerText.slice(0, -1);
    // wait
    await new Promise((resolve) => setTimeout(resolve, CHAR_DELAY));
  }

  // type in next
  for(let i = 0; i < next.length; i++) {
    typer.innerText += next[i];
    await new Promise((resolve) => setTimeout(resolve, CHAR_DELAY));
  }

  startBlink();

  // wait
  await new Promise((resolve) => setTimeout(resolve, WORD_DELAY));
  replaceTyper();
}

startBlink();
setTimeout(()=>{
  replaceTyper();
}, 4000);
</script><div class="h-8"></div><p class="text-[1.3rem] leading-normal dark:text-gray-300">Bun is a fast, <strong>incrementally adoptable</strong> all-in-one JavaScript, TypeScript &amp; JSX toolkit. Use individual tools like bun test or <strong>bun install in Node.js</strong> projects, or adopt the complete stack with a fast JavaScript runtime, bundler,<!-- --> <a class="underline decoration-pink-400/30 hover:decoration-pink-400" href="/docs/cli/test">test runner</a>, and<!-- --> <a class="underline decoration-pink-400/30 hover:decoration-pink-400" href="/package-manager">package manager</a> <!-- -->built in. Bun aims for 100% Node.js compatibility.</p><div class="sm:h-8"></div><div class="mt-0 hidden rounded-[5px] md:block InstallBox--desktop w-full"><div></div><p class="all-caps text-xl font-semibold dark:text-white">Install Bun v1.3.11</p><div class="mb-0 mt-[10px] flex flex-row items-center text-gray-200"><div class="mr-4 flex flex-row"><button class="cursor-pointer rounded-t-md bg-pink-400 px-[16px] py-[6px] text-center text-black" data-install-link="posix">Linux &amp; macOS</button><button class="cursor-pointer rounded-t-md  border-2 border-b-0 border-gray-500 bg-gray-700 px-[16px] py-[8px] text-center" data-install-link="windows">Windows</button></div><a id="install-source" href="https://bun.sh/install" target="_blank" class="text-small text-[0.9rem] text-gray-300 opacity-60">View install script</a></div><div><div data-install="posix" class="CodeBlock my-[10px] mt-0 rounded-tl-none border-2 border-pink-400 py-[20px] text-lg"><div class="relative CodeBlockShell "><div id="wDifIJtXHiPY:0"><pre class="shiki" style="background-color: #282A36"><code><span class="line"><span style="color: #F8F8F2">curl -fsSL https://bun.sh/install </span><span style="color: #FF79C6">|</span><span style="color: #F8F8F2"> bash</span></span></code></pre></div><div id="wDifIJtXHiPY:0:copy" class="CopyIcon copy absolute right-[6px] "><svg xmlns="http://www.w3.org/2000/svg" fill="none" 