`</span></div><div>    <span class="text-purple-400">SELECT</span> <span class="text-sky-300">title</span>,<!-- --> <span class="text-sky-300">image_key</span>,<!-- --> <span class="text-sky-300">content</span></div><div>    <span class="text-purple-400">FROM</span> <span class="text-sky-300">posts</span></div><div>    <span class="text-purple-400">WHERE</span> <span class="text-sky-300">slug</span> <span class="text-pink-400">=</span> <span class="text-gray-500">$<!-- -->{</span><span class="text-orange-300">params</span>.<span class="text-cyan-300">slug</span><span class="text-gray-500">}</span></div><div>  <span class="text-gray-500">`</span>;</div><div> </div><div>  <span class="text-pink-400">const</span> <span class="text-purple-300">imgUrl</span> =<!-- --> <span class="text-blue-300">s3</span>.<span class="text-yellow-400">file</span>(<span class="text-purple-300">post</span>.<span class="text-cyan-300">image_key</span>).<span class="text-yellow-400">presign</span>(<!-- -->{<span class="expandable-ellipsis mr-1 cursor-pointer select-none rounded bg-gray-800/50 px-1.5 py-0.5 text-xs text-gray-500 transition-colors hover:bg-gray-700/50 hover:text-gray-300" data-target="nextjs-code-expand">•••</span><span class="nextjs-code-expand hidden"><span class="text-cyan-300">expiresIn</span>:<!-- --> <span class="text-green-400">3600</span> </span>}<!-- -->);</div><div> </div><div>  <span class="text-pink-400">const</span> <span class="text-purple-300">wordCount</span> =<!-- --> <span class="text-pink-400">await</span> <span class="text-blue-300">$</span><span class="text-gray-500">`</span><span class="text-emerald-400">echo</span> <span class="text-gray-500">$<!-- -->{</span><span class="text-purple-300">post</span>.<span class="text-cyan-300">content</span><span class="text-gray-500">}</span> <span class="text-gray-400">|</span> <span class="text-emerald-400">wc</span> <span class="text-yellow-300">-w</span><span class="text-gray-500">`</span>;</div><div> </div><div>  <span class="text-pink-400">return</span> <!-- -->(</div><div>    <!-- -->&lt;<span class="text-green-300">div</span>&gt;</div><div>      <!-- -->&lt;<span class="text-green-300">h1</span>&gt;<!-- -->{<span class="text-purple-300">post</span>.<span class="text-cyan-300">title</span>}<!-- -->&lt;/<span class="text-green-300">h1</span>&gt;</div><div>      <!-- -->&lt;<span class="text-green-300">img</span> <span class="text-cyan-300">src</span>=<!-- -->{<span class="text-purple-300">imgUrl</span>}<!-- --> /<!-- -->&gt;</div><div>      <!-- -->&lt;<span class="text-green-300">p</span>&gt;<!-- -->Word count: <!-- -->{<span class="text-purple-300">wordCount</span>}<!-- -->&lt;/<span class="text-green-300">p</span>&gt;</div><div>    <!-- -->&lt;/<span class="text-green-300">div</span>&gt;</div><div>  );</div><div>}</div></div></div></div></div></div></div><script>document.querySelectorAll(".video-player").forEach(function(video){const playButton=video.parentElement.querySelector('[class*="play-button-"]');if(playButton){playButton.addEventListener("click",function(e){e.preventDefault();e.stopPropagation();const videoId=video.id;playButton.remove();const videoOverlay=document.querySelector(".video-overlay-"+videoId);if(videoOverlay){videoOverlay.remove()}document.querySelectorAll(".video-player").forEach(function(v){if(v!==video){v.pause()}});video.controls=true;video.play().catch(function(err){console.error("Play error:",err)})})}});document.querySelectorAll(".expandable-ellipsis").forEach(function(el){el.addEventListener("click",function(e){e.preventDefault();const target=this.getAttribute("data-target");const expandable=document.querySelector("."+target);if(expandable){if(expandable.classList.contains("hidden")){expandable.classList.remove("hidden");this.style.display="none"}else{expandable.classList.add("hidden");this.style.display="inline"}}})});</script></section><section class="dark mx-auto border-t-[2px] border-gray-800 bg-gray-950 px-[15px] py-[100px] lg:py-[150px]"><div class="mx-auto max-w-screen-xl"><div class="mb-16 text-center"><h2 class="text-4xl font-extrabold leading-tight text-pink-200 drop-shadow-[2px_2px_0px_rgba(var(--pink-800))] md:text-5xl">Full speed full-stack</h2><p class="mx-auto mt-6 max-w-2xl text-balance text-lg text-gray-300 md:text-xl">Fast frontend apps with Bun&#x27;s built-in high performance development server and production bundler. You&#x27;ve <i>never</i> <!-- -->seen hot-reloading this fast!</p></div><div class="flex flex-col gap-12 lg:flex-row lg:items-center lg:gap-16"><div class="flex-1 space-y-6"><h3 class="text-3xl font-bold text-white">Develop and ship frontend apps</h3><p class="text-lg leading-relaxed text-gray-300">Bun&#x27;s built-in bundler and dev server make frontend development fast and simple. Develop with instant hot reload, then ship optimized production builds—all with zero configuration.</p><div class="mt-6"><div class="overflow-hidden rounded-lg border border-pink-800/30 bg-gray-950 shadow-lg shadow-pink-900/10 "><div class="flex items-center rounded-t-lg border-b border-b-pink-800/40 bg-gray-900 px-3 py-1.5"><div class="flex items-center gap-2"><div class="h-2.5 w-2.5 rounded-full bg-gray-600"></div><div class="h-2.5 w-2.5 rounded-full bg-gray-600"></div><div class="h-2.5 w-2.5 rounded-full bg-gray-600"></div></div></div><div class="flex items-center justify-between gap-4 bg-gray-950 px-4 py-3"><div id="dVjQXKqEuFBK" class="font-mono text-sm text-gray-100 sm:text-base"><span class="select-none text-pink-400">$ </span><span class="text-white">bun init --react</span></div><button id="dVjQXKqEuFBK:copy" type="button" class="copy flex-shrink-0 cursor-pointer rounded-md p-1 transition-colors hover:bg-pink-900/20"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" aria-hidden="true" data-slot="icon" class="clipboard h-4 w-4 text-gray-400 transition-colors hover:text-pink-400"><path stroke-linecap="round" stroke-linejoin="round" d="M16.5 8.25V6a2.25 2.25 0 0 0-2.25-2.25H6A2.25 2.25 0 0 0 3.75 6v8.25A2.25 2.25 0 0 0 6 16.5h2.25m8.25-8.25H18a2.25 2.25 0 0 1 2.25 2.25V18A2.25 2.25 0 0 1 18 20.25h-7.5A2.25 2.25 0 0 1 8.25 18v-1.5m8.25-8.25h-6a2.25 2.25 0 0 0-2.25 2.25v6"></path></svg><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" aria-hidden="true" data-slot="icon" class="check hidden h-4 w-4 text-pink-400"><path stroke-linecap="round" stroke-linejoin="round" d="m4.5 12.75 6 6 9-13.5"></path></svg><script>
                document.addEventListener('DOMContentLoaded', () => {
                  const clicker = document.getElementById('dVjQXKqEuFBK:copy');
                  const code = document.getElementById('dVjQXKqEuFBK');
                  if (clicker && code) {
                    clicker.addEventListener('click', (ev) => {
                      const textContent = code.textContent.replace(/^\$\s*/, '').trim();
                      navigator.clipboard.writeText(textContent).then(() => {
                        clicker.querySelector('.clipboard').classList.add('hidden');
                        clicker.querySelector('.check').classList.remove('hidden');
                        setTimeout(() => {
                          clicker.querySelector('.clipboard').classList.remove('hidden');
                          clicker.querySelector('.check').classList.add('hidden');
                        }, 2000);
                      });
                    });
                  }
                });
              </script></button></div></div></div><div class="space-y-4"><div><h4 class="mb-2 text-xl font-semibold text-white">Start a dev server</h4><p class="text-gray-400">Run<!-- --> <code class="rounded bg-gray-800 px-2 py-1 text-pink-300">bun ./index.html</code> <!-- -->to start a dev server. TypeScript, JSX, React, and CSS imports work out of the box.</p></div><div><h4 class="mb-2 text-xl font-semibold text-white">Hot Module Replacement</h4><p class="text-gray-400">Built-in HMR preserves application state during development. Changes appear instantly—no manual refresh needed.</p></div><div><h4 class="mb-2 text-xl font-semibold text-white">Build for production</h4><p class="text-gray-400">Build optimized bundles with<!-- --> <code class="rounded bg-gray-800 px-2 py-1 text-pink-300">bun build ./index.html --production</code>. Tree-shaking, minification, and code splitting work out of the box.</p></div></div><div class="pt-4"><a href="/docs/bundler/html" class="inline-flex items-center gap-2 font-semibold text-pink-400 hover:text-pink-300">Learn more about frontend with Bun →</a></div></div><div class="flex-1"><div class="overflow-hidden rounded-lg border-2 border-gray-800 bg-gray-900 shadow-2xl"><video autoplay="" loop="" muted="" playsinline="" class="w-full"><source src="/bun-frontend-hmr-demo.mp4" type="video/mp4"/><source src="/bun-frontend-hmr-demo.webm" type="video/webm"/></video></div></div></div></div></section><section class="dark mx-auto flex flex-col items-center border-t-[2px] border-gray-800 bg-gray-900 px-[15px] py-[100px] lg:py-[150px]"><div class="overflow-hidden rounded-lg border border-pink-800/30 bg-gray-950 shadow-lg shadow-pink-900/10 inline-block"><div class="flex items-center rounded-t-lg border-b border-b-pink-800/40 bg-gray-900 px-3 py-1.5"><div class="flex items-center gap-2"><div class="h-2.5 w-2.5 rounded-full bg-gray-600"></div><div class="h-2.5 w-2.5 rounded-full bg-gray-600"></div><div class="h-2.5 w-2.5 rounded-full bg-gray-600">